const leads = $input.all().map(i => i.json);

// Group by agent
const byAgent = {};
leads.forEach(lead => {
  const agentEmail = lead.agent_email;
  if (!byAgent[agentEmail]) {
    byAgent[agentEmail] = {
      agent_name: lead.agent_name,
      agent_email: lead.agent_email,
      agent_phone: lead.agent_phone,
      leads: []
    };
  }
  byAgent[agentEmail].leads.push(lead);
});

// Create one reminder digest per agent
const result = Object.values(byAgent).map(agent => {
  const hotLeads = agent.leads.filter(l => l.lead_tier === 'hot');
  const warmLeads = agent.leads.filter(l => l.lead_tier === 'warm');
  const coldLeads = agent.leads.filter(l => l.lead_tier === 'cold');

  const fmt = (n) => 'R ' + Number(n).toLocaleString('en-ZA', { maximumFractionDigits: 0 });

  const emailHtml = `
<!DOCTYPE html>
<html>
<head><style>
body{font-family:Arial,sans-serif;color:#333;margin:0;background:#f4f4f4;}
.container{max-width:650px;margin:0 auto;background:white;}
.header{background:#1a472a;color:white;padding:25px;text-align:center;}
.section{padding:20px 25px;border-bottom:1px solid #eee;}
.section h3{margin:0 0 15px;color:#1a472a;font-size:15px;text-transform:uppercase;}
.lead-row{border:1px solid #e8e8e8;border-radius:8px;padding:14px;margin:8px 0;}
.hot{border-left:4px solid #e53e3e;}
.warm{border-left:4px solid #ed8936;}
.cold{border-left:4px solid #4299e1;}
.lead-name{font-weight:bold;font-size:15px;}
.lead-meta{color:#666;font-size:13px;margin:4px 0;}
.badge{padding:2px 8px;border-radius:10px;font-size:11px;font-weight:bold;}
.hot-badge{background:#fed7d7;color:#c53030;}
.warm-badge{background:#feebc8;color:#c05621;}
.cold-badge{background:#bee3f8;color:#2a69ac;}
.contact-btn{background:#1a472a;color:white;padding:8px 16px;text-decoration:none;border-radius:4px;font-size:13px;display:inline-block;margin:5px 5px 0 0;}
footer{background:#1a472a;color:rgba(255,255,255,0.7);padding:15px;text-align:center;font-size:12px;}
</style></head>
<body><div class="container">
<div class="header">
  <h2>Follow-up Reminders</h2>
  <p style="opacity:0.8;margin:5px 0 0;">${new Date().toLocaleDateString('en-ZA', { weekday: 'long', day: 'numeric', month: 'long' })}</p>
  <p style="opacity:0.9;margin:5px 0 0;font-size:18px;">Hi ${agent.agent_name} - You have ${agent.leads.length} follow-up${agent.leads.length > 1 ? 's' : ''} today</p>
</div>

${hotLeads.length > 0 ? `
<div class="section">
  <h3>HOT Leads (${hotLeads.length}) - Contact Today!</h3>
  ${hotLeads.map(l => `
  <div class="lead-row hot">
    <div class="lead-name">${l.first_name} ${l.last_name} <span class="badge hot-badge">HOT ${l.lead_score}/100</span></div>
    <div class="lead-meta">${l.lead_email} | ${l.lead_phone || 'No phone'}</div>
    <div class="lead-meta">Budget: ${l.budget > 0 ? fmt(l.budget) : 'Not specified'} | Timeline: ${l.timeline} | ${l.province}</div>
    <div class="lead-meta">${l.days_since_contact ? `Last contact: ${Math.round(l.days_since_contact)} days ago` : 'No contact yet'}</div>
    ${l.interested_property ? `<div class="lead-meta">Interested in: <a href="${l.interested_property_url}">${l.interested_property}</a></div>` : ''}
    ${l.reminder_note ? `<div class="lead-meta"><em>Note: ${l.reminder_note}</em></div>` : ''}
    <a href="mailto:${l.lead_email}" class="contact-btn">Send Email</a>
    ${l.lead_phone ? `<a href="tel:${l.lead_phone}" class="contact-btn" style="background:#2d6a4f;">Call</a>` : ''}
    <a href="https://puraestate.co.za/admin/leads/${l.lead_id}" class="contact-btn" style="background:#666;">View Profile</a>
  </div>`).join('')}
</div>` : ''}

${warmLeads.length > 0 ? `
<div class="section">
  <h3>Warm Leads (${warmLeads.length})</h3>
  ${warmLeads.map(l => `
  <div class="lead-row warm">
    <div class="lead-name">${l.first_name} ${l.last_name} <span class="badge warm-badge">WARM ${l.lead_score}/100</span></div>
    <div class="lead-meta">${l.lead_email} | ${l.lead_phone || 'No phone'}</div>
    <div class="lead-meta">Budget: ${l.budget > 0 ? fmt(l.budget) : 'Not specified'} | ${l.province}</div>
    <div class="lead-meta">${l.days_since_contact ? `Last contact: ${Math.round(l.days_since_contact)} days ago` : 'No contact yet'}</div>
    <a href="mailto:${l.lead_email}" class="contact-btn">Send Email</a>
    <a href="https://puraestate.co.za/admin/leads/${l.lead_id}" class="contact-btn" style="background:#666;">View Profile</a>
  </div>`).join('')}
</div>` : ''}

${coldLeads.length > 0 ? `
<div class="section">
  <h3>Cold Leads (${coldLeads.length})</h3>
  ${coldLeads.map(l => `
  <div class="lead-row cold">
    <div class="lead-name">${l.first_name} ${l.last_name} <span class="badge cold-badge">COLD ${l.lead_score}/100</span></div>
    <div class="lead-meta">${l.lead_email} | ${l.province}</div>
    <div class="lead-meta">${l.days_since_contact ? `Last contact: ${Math.round(l.days_since_contact)} days ago` : 'No contact yet'}</div>
    <a href="mailto:${l.lead_email}" class="contact-btn">Send Email</a>
    <a href="https://puraestate.co.za/admin/leads/${l.lead_id}" class="contact-btn" style="background:#666;">View Profile</a>
  </div>`).join('')}
</div>` : ''}

<footer>PuraEstate CRM | <a href="https://puraestate.co.za/admin/leads" style="color:#95d5b2;">Open CRM Dashboard</a></footer>
</div></body></html>`;

  const slackMessage = [
    `*Follow-up Reminder: ${agent.agent_name}*`,
    `You have ${agent.leads.length} leads to follow up today:`,
    hotLeads.length > 0 ? `:fire: ${hotLeads.length} HOT leads - contact today!` : '',
    warmLeads.length > 0 ? `:orange_circle: ${warmLeads.length} warm leads` : '',
    coldLeads.length > 0 ? `:blue_circle: ${coldLeads.length} cold leads` : '',
    `<https://puraestate.co.za/admin/leads|Open CRM Dashboard>`
  ].filter(Boolean).join('\n');

  return {
    json: {
      agent_name: agent.agent_name,
      agent_email: agent.agent_email,
      total_followups: agent.leads.length,
      hot_count: hotLeads.length,
      warm_count: warmLeads.length,
      cold_count: coldLeads.length,
      email_html: emailHtml,
      slack_message: slackMessage,
      subject: `Follow-up Reminders: ${agent.leads.length} leads need attention today`
    }
  };
});

return result;
